"use strict";(self.webpackChunkspanish_app=self.webpackChunkspanish_app||[]).push([[8756],{8756:e=>{e.exports=JSON.parse('{"35":{"words":[{"spanish":"seg\xfan fuentes cercanas","english":"according to sources close to the matter"},{"spanish":"se afirma que","english":"it is claimed that"},{"spanish":"presuntamente","english":"allegedly"},{"spanish":"de acuerdo con","english":"according to"},{"spanish":"el art\xedculo sostiene que","english":"the article argues that"},{"spanish":"la fuente primaria","english":"the primary source"},{"spanish":"verificar la informaci\xf3n","english":"to verify the information"},{"spanish":"contrastar versiones","english":"to compare versions"},{"spanish":"el sesgo editorial","english":"editorial bias"},{"spanish":"la desinformaci\xf3n","english":"misinformation"},{"spanish":"el bulo","english":"the hoax"},{"spanish":"el titular enga\xf1oso","english":"the misleading headline"},{"spanish":"contextualizar un dato","english":"to put a data point in context"},{"spanish":"una captura manipulada","english":"a manipulated screenshot"},{"spanish":"un testigo presencial","english":"an eyewitness"},{"spanish":"una declaraci\xf3n oficial","english":"an official statement"},{"spanish":"la atribuci\xf3n correcta","english":"proper attribution"},{"spanish":"la evidencia verificable","english":"verifiable evidence"},{"spanish":"una conclusi\xf3n precipitada","english":"a hasty conclusion"},{"spanish":"la cobertura medi\xe1tica","english":"media coverage"},{"spanish":"el rumor viral","english":"the viral rumor"},{"spanish":"la cadena de reenv\xedos","english":"the forwarding chain"},{"spanish":"sacar de contexto","english":"to take out of context"},{"spanish":"comprobar la fecha","english":"to check the date"},{"spanish":"identificar la autor\xeda","english":"to identify authorship"},{"spanish":"rastrear el origen","english":"to trace the origin"},{"spanish":"un medio fiable","english":"a reliable outlet"},{"spanish":"una fuente an\xf3nima","english":"an anonymous source"},{"spanish":"la edici\xf3n del video","english":"the video editing"},{"spanish":"una omisi\xf3n relevante","english":"a relevant omission"},{"spanish":"rectificar una noticia","english":"to correct a news story"},{"spanish":"difundir sin verificar","english":"to spread without verifying"},{"spanish":"un montaje digital","english":"a digital fabrication"},{"spanish":"el relato dominante","english":"the dominant narrative"},{"spanish":"la interpretaci\xf3n interesada","english":"a self-serving interpretation"},{"spanish":"los hechos confirmados","english":"the confirmed facts"},{"spanish":"una versi\xf3n no corroborada","english":"an uncorroborated version"},{"spanish":"hablar en condicional","english":"to use the conditional"},{"spanish":"citar textualmente","english":"to quote verbatim"},{"spanish":"reformular con cautela","english":"to rephrase cautiously"},{"spanish":"un dato incompleto","english":"an incomplete data point"},{"spanish":"alfabetizaci\xf3n medi\xe1tica","english":"media literacy"}],"conversations":[{"id":1,"topic":"Verificar un video viral antes de publicarlo","dialog":[{"speaker":"Luc\xeda","spanish":"Seg\xfan fuentes locales, el video que circula desde anoche mostrar\xeda el desbordamiento del r\xedo; sin embargo, nadie ha confirmado todav\xeda la fecha exacta de la grabaci\xf3n.","english":"According to local sources, the video circulating since last night would show the river overflowing; however, nobody has yet confirmed the exact date of the recording."},{"speaker":"Mateo","spanish":"Antes de publicarlo, verifica la ubicaci\xf3n y contrasta el paisaje con las im\xe1genes de archivo, porque un clip fuera de contexto puede alimentar la desinformaci\xf3n.","english":"Before publishing it, verify the location and compare the landscape with archive footage, because a clip taken out of context can fuel misinformation."},{"speaker":"Luc\xeda","spanish":"Ya compar\xe9 los edificios del fondo con fotos satelitales, y una vecina afirma que fue grabado ayer, aunque su testimonio sigue siendo una fuente \xfanica.","english":"I already compared the buildings in the background with satellite photos, and a neighbor states that it was recorded yesterday, although her testimony is still a single source."},{"speaker":"Mateo","spanish":"Bien, pero necesito una segunda confirmaci\xf3n. De acuerdo con protecci\xf3n civil, el caudal subi\xf3 esta madrugada, lo cual har\xeda plausible el video sin demostrarlo por completo.","english":"Good, but I need a second confirmation. According to civil protection, the water level rose early this morning, which would make the video plausible without proving it completely."},{"speaker":"Luc\xeda","spanish":"Tambi\xe9n encontr\xe9 una publicaci\xf3n anterior, presuntamente del mismo autor, donde se ve la misma calle seca hace tres d\xedas; por lo tanto, el material no parece reciclado de otro mes.","english":"I also found an earlier post, allegedly from the same author, showing the same street dry three days ago; therefore, the footage does not seem to have been recycled from another month."},{"speaker":"Mateo","spanish":"Entonces redacta que el video coincide con reportes recientes, pero aclara qu\xe9 hechos est\xe1n confirmados y cu\xe1les siguen en verificaci\xf3n.","english":"Then write that the video aligns with recent reports, but make clear which facts are confirmed and which are still being verified."}],"questions":[{"question":"\xbfPor qu\xe9 Mateo no quiere publicar el video de inmediato?","options":["Porque duda de que el r\xedo exista","Porque teme que el video est\xe9 fuera de contexto o incompleto","Porque la redacci\xf3n no publica im\xe1genes de desastres","Porque Luc\xeda no sabe usar fotos satelitales"],"answer":"Porque teme que el video est\xe9 fuera de contexto o incompleto","answerIndex":1},{"question":"\xbfQu\xe9 hallazgo de Luc\xeda fortalece m\xe1s la plausibilidad del video?","options":["Que una sola vecina lo comparti\xf3","Que encontr\xf3 una publicaci\xf3n previa del mismo lugar y el mismo autor","Que el video tiene m\xfasica dram\xe1tica","Que nadie cuestion\xf3 el clip en redes sociales"],"answer":"Que encontr\xf3 una publicaci\xf3n previa del mismo lugar y el mismo autor","answerIndex":1},{"question":"\xbfC\xf3mo quiere Mateo que se presente la informaci\xf3n al p\xfablico?","options":["Como un hecho totalmente confirmado","Como una sospecha sin valor informativo","Distinguiendo entre lo confirmado y lo que sigue en verificaci\xf3n","Sin mencionar ninguna fuente"],"answer":"Distinguiendo entre lo confirmado y lo que sigue en verificaci\xf3n","answerIndex":2}]},{"id":2,"topic":"Analizar un titular alarmista","dialog":[{"speaker":"Sof\xeda","spanish":"El art\xedculo sostiene que el transporte p\xfablico est\xe1 al borde del colapso, pero al leerlo completo vi que la fuente principal era un informe parcial.","english":"The article claims that public transport is on the verge of collapse, but when I read it fully I saw that the main source was only a partial report."},{"speaker":"Andr\xe9s","spanish":"A m\xed me pas\xf3 igual. El titular parece dise\xf1ado para alarmar, mientras que el cuerpo del texto admite que varias l\xedneas mejoraron su frecuencia este mes.","english":"The same thing happened to me. The headline seems designed to alarm, while the body of the article admits that several lines improved their frequency this month."},{"speaker":"Sof\xeda","spanish":"De hecho, los datos que omite sobre puntualidad cambian bastante la interpretaci\xf3n, porque el problema real parece concentrarse en dos rutas perif\xe9ricas.","english":"In fact, the punctuality data it leaves out changes the interpretation quite a bit, because the real problem seems concentrated on two outlying routes."},{"speaker":"Andr\xe9s","spanish":"Seg\xfan el sindicato, los retrasos se agravaron por falta de conductores; en cambio, la empresa dice que el ajuste de horarios ya est\xe1 reduciendo el impacto.","english":"According to the union, delays worsened because of a shortage of drivers; by contrast, the company says the schedule adjustment is already reducing the impact."},{"speaker":"Sof\xeda","spanish":"Por eso conviene contrastar ambas versiones y revisar qui\xe9n financia el medio, ya que el sesgo no siempre est\xe1 en lo que se dice, sino en lo que se calla.","english":"That is why it is useful to compare both versions and review who funds the outlet, since bias is not always in what is said, but in what is left unsaid."},{"speaker":"Andr\xe9s","spanish":"Exacto, y si compartimos la noticia, deber\xedamos a\xf1adir contexto para que nadie crea que todo el sistema fall\xf3 de un d\xeda para otro.","english":"Exactly, and if we share the story, we should add context so that nobody believes the entire system failed overnight."}],"questions":[{"question":"\xbfQu\xe9 problema detectan Sof\xeda y Andr\xe9s en el titular?","options":["Que usa demasiados t\xe9rminos t\xe9cnicos","Que exagera una situaci\xf3n m\xe1s limitada de lo que parece","Que cita demasiadas fuentes primarias","Que describe mejoras en lugar de fallos"],"answer":"Que exagera una situaci\xf3n m\xe1s limitada de lo que parece","answerIndex":1},{"question":"\xbfQu\xe9 dato omitido menciona Sof\xeda como relevante para interpretar mejor la noticia?","options":["Los datos sobre puntualidad","La edad de los conductores","El precio del combustible","El color de los autobuses nuevos"],"answer":"Los datos sobre puntualidad","answerIndex":0},{"question":"\xbfQu\xe9 actitud recomiendan adoptar si se comparte el art\xedculo?","options":["Difundirlo sin comentario para no influir","Esperar a que desaparezca de las redes","A\xf1adir contexto para evitar una impresi\xf3n distorsionada","Citar solo el titular y no el contenido"],"answer":"A\xf1adir contexto para evitar una impresi\xf3n distorsionada","answerIndex":2}]},{"id":3,"topic":"Debate sobre una noticia basada en una fuente an\xf3nima","dialog":[{"speaker":"Clara","spanish":"Se afirma que el ministerio cerrar\xe1 tres centros de salud, pero la noticia se apoya casi por completo en una fuente an\xf3nima.","english":"It is being claimed that the ministry will close three health centers, but the story relies almost entirely on an anonymous source."},{"speaker":"Diego","spanish":"Eso me hace desconfiar, aunque la periodista que la firma suele rectificar cuando detecta un dato incompleto o una atribuci\xf3n d\xe9bil.","english":"That makes me suspicious, although the journalist who signed it usually corrects stories when she detects incomplete data or weak attribution."},{"speaker":"Clara","spanish":"De acuerdo con el documento filtrado, habr\xeda un plan de reorganizaci\xf3n; no obstante, el texto no menciona cierres inmediatos, sino una evaluaci\xf3n preliminar.","english":"According to the leaked document, there would be a reorganization plan; nevertheless, the text does not mention immediate closures, but rather a preliminary evaluation."},{"speaker":"Diego","spanish":"Entonces el problema quiz\xe1 no sea la existencia del documento, sino el salto entre lo que sugiere y lo que el titular asegura.","english":"Then the problem may not be the existence of the document, but the jump between what it suggests and what the headline asserts."},{"speaker":"Clara","spanish":"Exactamente. Adem\xe1s, ning\xfan portavoz confirm\xf3 la medida, por lo cual hablar en condicional ser\xeda m\xe1s honesto que presentar la decisi\xf3n como definitiva.","english":"Exactly. Moreover, no spokesperson confirmed the measure, which is why using the conditional would be more honest than presenting the decision as final."},{"speaker":"Diego","spanish":"Esa diferencia es clave, porque mucha gente solo lee el encabezado y acaba difundiendo una versi\xf3n no corroborada como si fuera un hecho cerrado.","english":"That difference is crucial, because many people only read the headline and end up spreading an uncorroborated version as if it were a settled fact."}],"questions":[{"question":"\xbfQu\xe9 objeci\xf3n principal plantea Clara sobre la noticia?","options":["Que el documento filtrado est\xe1 escrito en otro idioma","Que depende demasiado de una fuente an\xf3nima y de una interpretaci\xf3n fuerte del titular","Que la periodista nunca corrige errores","Que los centros de salud ya fueron cerrados hace a\xf1os"],"answer":"Que depende demasiado de una fuente an\xf3nima y de una interpretaci\xf3n fuerte del titular","answerIndex":1},{"question":"\xbfQu\xe9 diferencia subraya Diego entre el documento y el titular?","options":["Que el documento confirma m\xe1s cierres que el titular","Que el documento habla de compras m\xe9dicas, no de salud p\xfablica","Que el titular afirma m\xe1s de lo que realmente sugiere el documento","Que ambos textos son id\xe9nticos en contenido y tono"],"answer":"Que el titular afirma m\xe1s de lo que realmente sugiere el documento","answerIndex":2},{"question":"\xbfPor qu\xe9 Clara considera m\xe1s honesto hablar en condicional?","options":["Porque ning\xfan portavoz ha confirmado la medida como definitiva","Porque as\xed la noticia parece m\xe1s dram\xe1tica","Porque el ministerio prohibi\xf3 usar verbos en presente","Porque el documento carece de fecha y firma oficial"],"answer":"Porque ning\xfan portavoz ha confirmado la medida como definitiva","answerIndex":0}]},{"id":4,"topic":"Desmentir un mensaje reenviado en familia","dialog":[{"speaker":"Elena","spanish":"Mi t\xeda reenvi\xf3 un mensaje que dice que varias marcas de leche infantil est\xe1n contaminadas, pero no cita ni una fuente oficial.","english":"My aunt forwarded a message saying that several brands of infant formula are contaminated, but it does not cite a single official source."},{"speaker":"Pablo","spanish":"Yo tambi\xe9n lo recib\xed. Presuntamente proviene de un trabajador del sector, aunque ese tipo de atribuci\xf3n an\xf3nima suele usarse en los bulos para parecer cre\xedble.","english":"I received it too. It allegedly comes from a worker in the industry, although that kind of anonymous attribution is often used in hoaxes to seem credible."},{"speaker":"Elena","spanish":"Busqu\xe9 la alerta en la agencia sanitaria y no encontr\xe9 nada; en cambio, s\xed vi un comunicado antiguo sobre un lote distinto retirado el a\xf1o pasado.","english":"I searched for the alert on the health agency\'s site and found nothing; by contrast, I did see an old statement about a different batch that was withdrawn last year."},{"speaker":"Pablo","spanish":"Eso explicar\xeda por qu\xe9 la captura parece real y, sin embargo, induce a error: mezcla un hecho verdadero con una advertencia actual que nadie ha emitido.","english":"That would explain why the screenshot looks real and yet is misleading: it mixes a true fact with a current warning that nobody has issued."},{"speaker":"Elena","spanish":"Entonces responder\xe9 en el grupo que la informaci\xf3n est\xe1 sacada de contexto y compartir\xe9 el enlace oficial para evitar m\xe1s reenv\xedos.","english":"Then I will reply in the group that the information has been taken out of context and share the official link to prevent more forwarding."},{"speaker":"Pablo","spanish":"Buena idea. Verificar antes de alarmar a la familia es una forma concreta de frenar la desinformaci\xf3n.","english":"Good idea. Verifying before alarming the family is a concrete way to slow misinformation."}],"questions":[{"question":"\xbfQu\xe9 hace sospechoso el mensaje reenviado para Elena y Pablo?","options":["Que cita demasiadas declaraciones oficiales","Que no menciona una fuente oficial y usa una atribuci\xf3n an\xf3nima","Que est\xe1 escrito con un lenguaje demasiado t\xe9cnico","Que incluye una fecha muy reciente y verificable"],"answer":"Que no menciona una fuente oficial y usa una atribuci\xf3n an\xf3nima","answerIndex":1},{"question":"\xbfQu\xe9 descubre Elena al verificar la informaci\xf3n?","options":["Que existe una alerta actual id\xe9ntica","Que todas las marcas fueron retiradas ayer","Que hay un comunicado antiguo sobre otro lote y no una alerta nueva","Que la agencia sanitaria cerr\xf3 su p\xe1gina web"],"answer":"Que hay un comunicado antiguo sobre otro lote y no una alerta nueva","answerIndex":2},{"question":"\xbfQu\xe9 estrategia decide seguir Elena en el grupo familiar?","options":["Ignorar el mensaje para no crear discusi\xf3n","Pedir que eliminen todos los enlaces del grupo","Compartir el enlace oficial y explicar que el contenido est\xe1 fuera de contexto","Volver a reenviar la captura con un comentario ir\xf3nico"],"answer":"Compartir el enlace oficial y explicar que el contenido est\xe1 fuera de contexto","answerIndex":2}]}],"stories":[{"id":1,"title":"El audio que cerraba la escuela","sentences":[{"spanish":"Un domingo por la noche empez\xf3 a circular un audio en el que una voz an\xf3nima afirmaba que la escuela del barrio cerrar\xeda por una supuesta plaga.","english":"On a Sunday night, an audio clip started circulating in which an anonymous voice claimed that the neighborhood school would close because of an alleged infestation."},{"spanish":"Muchas familias lo reenviaron sin verificar, porque la persona que hablaba parec\xeda conocer detalles internos y usaba un tono muy seguro.","english":"Many families forwarded it without verifying, because the person speaking seemed to know internal details and used a very confident tone."},{"spanish":"Sin embargo, una madre comprob\xf3 la fecha del archivo y descubri\xf3 que el mismo mensaje ya hab\xeda circulado dos a\xf1os antes en otra ciudad.","english":"However, one mother checked the file\'s date and discovered that the same message had already circulated two years earlier in another city."},{"spanish":"Despu\xe9s llam\xf3 a la direcci\xf3n, cuya respuesta oficial confirm\xf3 que las clases seguir\xedan con normalidad y que no exist\xeda ninguna alerta sanitaria.","english":"She then called the administration, whose official response confirmed that classes would continue normally and that no health alert existed."},{"spanish":"Gracias a esa verificaci\xf3n, el rumor perdi\xf3 fuerza y varias personas entendieron que un mensaje convincente no siempre contiene hechos confirmados.","english":"Thanks to that verification, the rumor lost momentum and several people understood that a convincing message does not always contain confirmed facts."}]},{"id":2,"title":"La entrevista recortada","sentences":[{"spanish":"Un programa de debate public\xf3 un fragmento de entrevista en el que una cient\xedfica parec\xeda afirmar que una vacuna era in\xfatil.","english":"A debate program published an interview clip in which a scientist appeared to claim that a vaccine was useless."},{"spanish":"El corte se volvi\xf3 viral porque reforzaba el relato dominante de varios grupos que ya desconfiaban de las instituciones sanitarias.","english":"The clip went viral because it reinforced the dominant narrative of several groups that already distrusted health institutions."},{"spanish":"No obstante, la versi\xf3n completa mostraba que la experta se refer\xeda solo a una dosis antigua cuya eficacia hab\xeda disminuido con nuevas variantes.","english":"Nevertheless, the full version showed that the expert was referring only to an older dose whose effectiveness had declined with new variants."},{"spanish":"Cuando algunos periodistas citaron textualmente el pasaje entero, qued\xf3 claro que el video hab\xeda sido editado para producir una conclusi\xf3n precipitada.","english":"When some journalists quoted the entire passage verbatim, it became clear that the video had been edited to produce a hasty conclusion."},{"spanish":"A partir de entonces, varios espectadores empezaron a exigir contexto antes de compartir clips que parecieran demasiado perfectos para confirmar sus prejuicios.","english":"From that point on, several viewers began demanding context before sharing clips that seemed too perfect for confirming their biases."}]},{"id":3,"title":"La noticia que tuvo que corregirse","sentences":[{"spanish":"Un medio digital public\xf3 de madrugada que un puente nuevo presentaba grietas graves, de acuerdo con una fuente t\xe9cnica que pidi\xf3 anonimato.","english":"A digital outlet reported overnight that a new bridge had serious cracks, according to a technical source who asked to remain anonymous."},{"spanish":"La noticia gener\xf3 alarma inmediata, y muchos usuarios la difundieron como si los hechos confirmados ya incluyeran un riesgo de derrumbe.","english":"The story caused immediate alarm, and many users spread it as if the confirmed facts already included a risk of collapse."},{"spanish":"Horas despu\xe9s, una inspecci\xf3n oficial explic\xf3 que las marcas observadas correspond\xedan a un material superficial que se sustitu\xeda habitualmente durante las primeras semanas.","english":"Hours later, an official inspection explained that the marks observed corresponded to a surface material that is routinely replaced during the first weeks."},{"spanish":"El medio rectific\xf3 la noticia y admiti\xf3 que hab\xeda formulado el titular con m\xe1s contundencia de la que permit\xeda la evidencia verificable.","english":"The outlet corrected the story and admitted that it had framed the headline more forcefully than the verifiable evidence allowed."},{"spanish":"Aunque la correcci\xf3n fue p\xfablica, el primer impacto ya hab\xeda dejado una impresi\xf3n duradera en lectores que no volvieron a revisar el asunto.","english":"Although the correction was public, the initial impact had already left a lasting impression on readers who never checked the issue again."}]}],"speaking":{"title":"Hablar sobre noticias, sesgo y verificaci\xf3n","description":"Practica discurso referido, verificaci\xf3n de fuentes y alfabetizaci\xf3n medi\xe1tica.","questions_and_answers":[{"question":{"spanish":"Explica por qu\xe9 no compartir\xedas una noticia de inmediato.","english":"Explain why you would not share a news story immediately."},"answer":{"spanish":"No la compartir\xeda de inmediato porque primero necesito verificar la fuente, comprobar la fecha y contrastar si otros medios fiables dicen lo mismo.","english":"I would not share it immediately because I first need to verify the source, check the date, and compare whether other reliable outlets say the same thing."}},{"question":{"spanish":"Resume una noticia usando discurso referido con cautela.","english":"Summarize a news story using cautious reported speech."},"answer":{"spanish":"Seg\xfan fuentes locales, se habr\xeda producido un corte el\xe9ctrico en la zona norte, aunque las autoridades todav\xeda no han confirmado la causa.","english":"According to local sources, there may have been a power outage in the northern area, although authorities have not yet confirmed the cause."}},{"question":{"spanish":"Describe qu\xe9 es un titular enga\xf1oso.","english":"Describe what a misleading headline is."},"answer":{"spanish":"Un titular enga\xf1oso es aquel que simplifica o exagera los hechos confirmados para provocar una reacci\xf3n m\xe1s fuerte de la que justifican los datos.","english":"A misleading headline is one that simplifies or exaggerates the confirmed facts to provoke a stronger reaction than the data justify."}},{"question":{"spanish":"Di c\xf3mo verificar\xedas un video viral.","english":"Say how you would verify a viral video."},"answer":{"spanish":"Verificar\xeda el video rastreando su origen, comparando la ubicaci\xf3n con im\xe1genes previas y buscando una declaraci\xf3n oficial que respalde el contexto.","english":"I would verify the video by tracing its origin, comparing the location with earlier images, and looking for an official statement that supports the context."}},{"question":{"spanish":"Explica por qu\xe9 una fuente an\xf3nima requiere cautela.","english":"Explain why an anonymous source requires caution."},"answer":{"spanish":"Una fuente an\xf3nima requiere cautela porque puede aportar informaci\xf3n valiosa, pero sin una atribuci\xf3n correcta es m\xe1s dif\xedcil medir su fiabilidad y sus intereses.","english":"An anonymous source requires caution because it may provide valuable information, but without proper attribution it is harder to assess its reliability and interests."}},{"question":{"spanish":"Habla de una vez en que una noticia te pareci\xf3 sesgada.","english":"Talk about a time when a news story seemed biased to you."},"answer":{"spanish":"Una vez le\xed un reportaje que omit\xeda datos clave sobre vivienda, y ese silencio produc\xeda un sesgo editorial m\xe1s claro que sus opiniones expl\xedcitas.","english":"Once I read a report that omitted key housing data, and that silence created a clearer editorial bias than its explicit opinions."}},{"question":{"spanish":"Menciona qu\xe9 har\xedas antes de reenviar una alerta preocupante.","english":"Mention what you would do before forwarding a worrying alert."},"answer":{"spanish":"Antes de reenviar una alerta, comprobar\xeda si procede de una instituci\xf3n reconocida y si el mensaje reproduce un comunicado actual en lugar de uno antiguo.","english":"Before forwarding an alert, I would check whether it comes from a recognized institution and whether the message reproduces a current statement rather than an old one."}},{"question":{"spanish":"Define la desinformaci\xf3n con tus palabras.","english":"Define misinformation in your own words."},"answer":{"spanish":"La desinformaci\xf3n es la difusi\xf3n de contenido falso o enga\xf1oso que, presuntamente informativo, termina distorsionando la comprensi\xf3n p\xfablica de un hecho.","english":"Misinformation is the spread of false or misleading content that, while supposedly informative, ends up distorting the public understanding of an event."}},{"question":{"spanish":"Explica por qu\xe9 importa contextualizar un dato.","english":"Explain why it matters to put a data point in context."},"answer":{"spanish":"Contextualizar un dato importa porque una cifra aislada puede apoyar una conclusi\xf3n precipitada, mientras que su contexto revela l\xedmites y comparaciones relevantes.","english":"Putting a data point in context matters because an isolated figure can support a hasty conclusion, whereas its context reveals limits and relevant comparisons."}},{"question":{"spanish":"Cuenta c\xf3mo reaccionar\xedas ante una captura manipulada.","english":"Tell how you would react to a manipulated screenshot."},"answer":{"spanish":"Si sospechara que una captura est\xe1 manipulada, buscar\xeda la publicaci\xf3n original y evitar\xeda comentar como si los hechos ya estuvieran confirmados.","english":"If I suspected a screenshot was manipulated, I would look for the original post and avoid commenting as if the facts had already been confirmed."}},{"question":{"spanish":"Di qu\xe9 significa hablar en condicional en una noticia.","english":"Say what it means to use the conditional in a news story."},"answer":{"spanish":"Hablar en condicional significa reconocer que una informaci\xf3n todav\xeda no ha sido corroborada y que, por lo tanto, debe presentarse con cautela.","english":"Using the conditional means recognizing that a piece of information has not yet been corroborated and therefore must be presented cautiously."}},{"question":{"spanish":"Explica qu\xe9 te hace confiar en un medio fiable.","english":"Explain what makes you trust a reliable outlet."},"answer":{"spanish":"Conf\xedo m\xe1s en un medio fiable cuando cita fuentes primarias, corrige errores con transparencia y diferencia claramente entre an\xe1lisis y hechos confirmados.","english":"I trust a reliable outlet more when it cites primary sources, corrects errors transparently, and clearly distinguishes analysis from confirmed facts."}},{"question":{"spanish":"Resume una discusi\xf3n sobre un bulo familiar.","english":"Summarize a discussion about a family hoax."},"answer":{"spanish":"En mi familia circul\xf3 un bulo sobre salud y, despu\xe9s de consultar a la agencia oficial, expliqu\xe9 que el mensaje mezclaba un hecho antiguo con una advertencia falsa.","english":"A health hoax circulated in my family, and after consulting the official agency, I explained that the message mixed an old fact with a false warning."}},{"question":{"spanish":"Habla de la diferencia entre un testigo y una prueba verificable.","english":"Talk about the difference between a witness and verifiable evidence."},"answer":{"spanish":"Un testigo puede aportar contexto inmediato, pero la prueba verificable permite contrastar su relato y reducir el riesgo de interpretaci\xf3n interesada.","english":"A witness can provide immediate context, but verifiable evidence makes it possible to test that account and reduce the risk of a self-serving interpretation."}},{"question":{"spanish":"Explica por qu\xe9 los sesgos no siempre son evidentes.","english":"Explain why biases are not always obvious."},"answer":{"spanish":"Los sesgos no siempre son evidentes porque a veces aparecen en las omisiones relevantes, en la selecci\xf3n de expertos o en el orden de los datos.","english":"Biases are not always obvious because they sometimes appear in relevant omissions, the selection of experts, or the order of the data."}},{"question":{"spanish":"Di c\xf3mo rectificar\xedas una informaci\xf3n incorrecta.","english":"Say how you would correct inaccurate information."},"answer":{"spanish":"Rectificar\xeda la informaci\xf3n citando la fuente correcta, explicando el error y dejando claro qu\xe9 parte del relato anterior no estaba corroborada.","english":"I would correct the information by citing the correct source, explaining the error, and making clear which part of the previous account was not corroborated."}},{"question":{"spanish":"Describe una noticia que exigir\xeda varias fuentes.","english":"Describe a story that would require several sources."},"answer":{"spanish":"Una denuncia sobre corrupci\xf3n exigir\xeda varias fuentes porque las acusaciones graves no deber\xedan difundirse bas\xe1ndose en una sola versi\xf3n no corroborada.","english":"An allegation of corruption would require several sources because serious accusations should not be spread based on a single uncorroborated version."}},{"question":{"spanish":"Habla de por qu\xe9 la autor\xeda importa en internet.","english":"Talk about why authorship matters online."},"answer":{"spanish":"La autor\xeda importa en internet porque identificar qui\xe9n publica permite evaluar intereses, trayectoria y posibles motivos para difundir un contenido dudoso.","english":"Authorship matters online because identifying who publishes something allows us to evaluate interests, track record, and possible motives for spreading doubtful content."}},{"question":{"spanish":"Explica qu\xe9 es la alfabetizaci\xf3n medi\xe1tica.","english":"Explain what media literacy is."},"answer":{"spanish":"La alfabetizaci\xf3n medi\xe1tica es la capacidad de leer, cuestionar y verificar mensajes p\xfablicos en lugar de aceptarlos solo porque confirman lo que uno ya piensa.","english":"Media literacy is the ability to read, question, and verify public messages instead of accepting them simply because they confirm what one already thinks."}},{"question":{"spanish":"Cuenta c\xf3mo ayudar\xedas a otra persona a contrastar una noticia.","english":"Tell how you would help someone else cross-check a news story."},"answer":{"spanish":"Ayudar\xeda a otra persona a contrastar una noticia buscando la fuente primaria, comparando medios distintos y reformulando con cautela lo que todav\xeda no est\xe1 confirmado.","english":"I would help someone else compare a news story by finding the primary source, comparing different outlets, and cautiously rephrasing what has not yet been confirmed."}}]}}}')}}]);